dslRule:
/*!id: deprecate-for-removal>
<!description: Add forRemoval and since attributes to @Deprecated annotations, prompting for the removal date.>
<!severity: info>
<!minJavaVersion: 9>
<!tags: annotations, modernization, java9>

@java.lang.Deprecated :: sourceVersionGE(9)
=> @java.lang.Deprecated(forRemoval = true, since = "YYYY-MM")
;;

dslRuleAfterChange:
/*!id: modernize-rescaling-activation>
<!description: Update monitor-specific rescaling activation to use system property instead of Display method.>
<!severity: warning>
<!minJavaVersion: 8>
<!tags: eclipse, ui, windows, rescaling>

method org.eclipse.ui.internal.Workbench.setRescaleAtRuntimePropertyFromPreference($display) :: hasModifier($display, "final")
=>
private static void setRescaleAtRuntimePropertyFromPreference() {
    if (java.lang.System.getProperty("swt.autoScale.updateOnRuntime") != null) {
        org.eclipse.ui.internal.WorkbenchPlugin.log(org.eclipse.core.runtime.StatusUtil.newStatus(org.eclipse.core.runtime.IStatus.WARNING, "swt.autoScale.updateOnRuntime"
                + " is configured (e.g., via the INI), but the according preference should be preferred instead.",
                new java.lang.RuntimeException()));
    } else {
        boolean rescaleAtRuntime = org.eclipse.ui.preferences.PrefUtil.getAPIPreferenceStore()
                .getBoolean("org.eclipse.ui.workbench.RESCALING_AT_RUNTIME");
        java.lang.System.setProperty("swt.autoScale.updateOnRuntime", java.lang.Boolean.toString(rescaleAtRuntime));
    }
}
;;

dslRule:
/*!id: mark-deprecated-for-removal-date
<!description: Mark @Deprecated annotations with forRemoval=true and a 'since' date>
<!severity: warning>
<!minJavaVersion: 9>
<!tags: modernization, deprecated, api-management>

@java.lang.Deprecated :: sourceVersionGE(9)
=> @java.lang.Deprecated(forRemoval = true, since = "2025-03")
;;
